const TIME_SLOTS = ["08:00 - 10:00","10:00 - 12:00","12:00 - 14:00","14:00 - 16:00","16:00 - 18:00","18:00 - 20:00"];
const CATEGORIES = [{id:"all",label:"Tous",icon:"◈"},{id:"eco",label:"Entrée de gamme",icon:"🚗"},{id:"utility",label:"Utilitaire",icon:"🚐"},{id:"minibus",label:"Mini-bus",icon:"🚌"},{id:"bus",label:"Bus",icon:"🚍"}];

