let currentUser = null;
let authMode = "login";
let currentPage = "home";
let currentFilter = "all";
let currentAdminTab = "reservations";
let reservations = [];
let allUsers = [{id:1,name:"Admin",email:"admin@lylamobility.fr",password:"admin",role:"admin",subscription:"gold"}];



function notify(msg, type="success") {
    const el = document.getElementById("notification");
    el.textContent = msg;
    el.style.background = type==="error"?"#EF4444":type==="info"?"#60A5FA":"#34D399";
    el.classList.remove("hidden");
    setTimeout(()=> el.classList.add("hidden"), 3500);
}

function $(id) { return document.getElementById(id); }



function showPage(page) {
    currentPage = page;
    document.querySelectorAll(".page").forEach(p => p.classList.remove("active"));
    const el = $("page-"+page);
    if (el) el.classList.add("active");
    renderNav();
    if (page==="vehicles") renderVehicles();
    if (page==="reservation") renderReservation();
    if (page==="status") renderStatus();
    if (page==="subscriptions") renderSubscriptions();
    if (page==="admin") renderAdmin();
    window.scrollTo(0,0);
}

function renderNav() {
    const items = [
        {id:"home",label:"Accueil"},{id:"vehicles",label:"Véhicules"},{id:"reservation",label:"Réservation"},
        {id:"status",label:"Mes réservations"},{id:"subscriptions",label:"Abonnements"}
    ];
    if (currentUser && currentUser.role==="admin") items.push({id:"admin",label:"Admin"});

    $("navLinks").innerHTML = items.map(item =>
        `<button class="nav-btn ${currentPage===item.id?'active':''}" onclick="showPage('${item.id}')">${item.label}</button>`
    ).join("");

    if (currentUser) {
        const sub = SUBSCRIPTIONS.find(s=>s.id===currentUser.subscription);
        $("navAuth").innerHTML = `
      <div class="nav-user">
        <div class="nav-user-info">
          <div class="nav-user-name">${currentUser.name}</div>
          <div class="nav-user-sub">${sub?sub.name:'Sans abonnement'}</div>
        </div>
        <button class="btn-icon" onclick="logout()" title="Déconnexion">⏻</button>
      </div>`;
        $("heroRegisterBtn").classList.add("hidden");
    } else {
        $("navAuth").innerHTML = `<button class="btn-primary btn-sm" onclick="openAuth('login')">👤 Connexion</button>`;
        $("heroRegisterBtn").classList.remove("hidden");
    }
}



function openAuth(mode) {
    authMode = mode;
    $("authModal").classList.remove("hidden");
    $("authEmail").value = ""; $("authPassword").value = "";
    if (mode==="login") {
        $("authTitle").textContent = "Connexion";
        $("authName").classList.add("hidden");
        $("authSubmitBtn").textContent = "Se connecter";
        $("authSwitchText").textContent = "Pas de compte ? ";
        $("authSwitchLink").textContent = "S'inscrire";
    } else {
        $("authTitle").textContent = "Inscription";
        $("authName").classList.remove("hidden");
        $("authName").value = "";
        $("authSubmitBtn").textContent = "Créer mon compte";
        $("authSwitchText").textContent = "Déjà un compte ? ";
        $("authSwitchLink").textContent = "Se connecter";
    }
}
function closeAuth() { $("authModal").classList.add("hidden"); }
function toggleAuthMode() { openAuth(authMode==="login"?"register":"login"); }

function submitAuth() {
    const email = $("authEmail").value.trim();
    const password = $("authPassword").value.trim();
    if (authMode==="login") {
        const found = allUsers.find(u=>u.email===email&&u.password===password);
        if (found) { currentUser=found; closeAuth(); notify("Bienvenue, "+found.name+" !"); renderNav(); showPage(currentPage); }
        else notify("Identifiants incorrects.","error");
    } else {
        const name = $("authName").value.trim();
        if (!name||!email||!password) { notify("Remplissez tous les champs.","error"); return; }
        if (allUsers.find(u=>u.email===email)) { notify("Cet email est déjà utilisé.","error"); return; }
        const newUser = {id:Date.now(),name,email,password,role:"user",subscription:null};
        allUsers.push(newUser);
        currentUser = newUser;
        closeAuth(); notify("Compte créé ! Bienvenue, "+name+" !"); renderNav(); showPage(currentPage);
    }
}

function logout() { currentUser=null; showPage("home"); notify("Déconnecté.","info"); renderNav(); }



function renderCategories() {
    const cats = [
        {icon:"🚗",title:"Entrée de gamme",desc:"Citadines économiques pour vos trajets quotidiens",count:VEHICLES.filter(v=>v.category==="eco").length},
        {icon:"🚐",title:"Utilitaires",desc:"Pour les professionnels et les déménagements",count:VEHICLES.filter(v=>v.category==="utility").length},
        {icon:"🚌",title:"Mini-bus",desc:"Sorties en groupe jusqu'à 9 places",count:VEHICLES.filter(v=>v.category==="minibus").length},
        {icon:"🚍",title:"Bus",desc:"Grands groupes et voyages organisés",count:VEHICLES.filter(v=>v.category==="bus").length},
    ];
    $("categoriesGrid").innerHTML = cats.map(c=>`
    <div class="card cat-card" onclick="showPage('vehicles')">
      <div class="cat-icon">${c.icon}</div>
      <h3 class="cat-title">${c.title}</h3>
      <p class="cat-desc">${c.desc}</p>
      <span class="cat-link">${c.count} véhicules →</span>
    </div>
  `).join("");
}



